motion.css_snippet:
/* HOSQ Motion Tokens */
:root {
  --motion-default: 300ms cubic-bezier(0.25, 0.46, 0.45, 0.94);
  --motion-fast: 150ms ease;
  --motion-slow: 500ms cubic-bezier(0.22, 1, 0.36, 1);
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

responsive.css_snippet:
/* HOSQ Responsive Type Scale */
:root {
  --fluid-display: clamp(40px, 5vw + 16px, 72px);
  --fluid-h1: clamp(28px, 3.5vw + 10px, 48px);
  --fluid-h2: clamp(24px, 2.5vw + 10px, 36px);
  --fluid-h3: clamp(20px, 1.5vw + 10px, 24px);
  --fluid-h4: clamp(18px, 1vw + 12px, 20px);
  --fluid-body-lg: clamp(16px, 0.5vw + 14px, 18px);
  --fluid-section-py: clamp(48px, 8vw, 96px);
  --fluid-section-px: clamp(16px, 5vw, 64px);
  --fluid-card-padding: clamp(16px, 2vw, 24px);
}

css_custom_properties:
:root {
  /* === HOSQ Brand Colors === */
  --brand-primary: #FF6F55;
  --brand-secondary: #C47CF1;
  --brand-accent: #14B672;
  --brand-accent-blue: #56A4CB;
  --brand-accent-pink: #E770C3;

  /* Neutrals (warm-tinted) */
  --brand-neutral-darkest: #231F20;
  --brand-neutral-dark: #4A4545;
  --brand-neutral-readable-mid: #6B6566;
  --brand-neutral-mid: #9A9596; /* DECORATIVE ONLY */
  --brand-neutral-light: #C5C4C3; /* DECORATIVE ONLY */
  --brand-neutral-lightest: #EBE2D6;

  /* Backgrounds */
  --brand-bg-page: #FFFFFF;
  --brand-bg-surface: #EBE2D6;
  --brand-bg-surface-warm: #F1E8DB;
  --brand-bg-surface-blush: #E8DCD4;
  --brand-bg-elevated: #FFFFFF;
  --brand-bg-inverse: #231F20;

  /* Semantic */
  --brand-success: #14B672;
  --brand-warning: #F0C3B3;
  --brand-error: #FF6F55;
  --brand-info: #56A4CB;

  /* Gradients */
  --brand-gradient-primary: linear-gradient(135deg, #FF6F55, #C47CF1);
  --brand-gradient-full: linear-gradient(135deg, #FF6F55, #C47CF1, #14B672);
  --brand-gradient-surface: linear-gradient(180deg, #F1E8DB, #EBE2D6);

  /* === Typography === */
  --brand-font-display: 'Austin Cy', Georgia, 'Times New Roman', serif;
  --brand-font-heading: 'Cera Pro', 'DM Sans', 'Inter', Arial, sans-serif;
  --brand-font-body: 'Cera Pro', 'DM Sans', 'Inter', Arial, sans-serif;

  /* Type Scale: 72→48→36→24→20→18→16→14→12 */
  --brand-display-size: 72px;
  --brand-display-weight: 700;
  --brand-display-line-height: 1.05;
  --brand-display-letter-spacing: -0.02em;

  --brand-h1-size: 48px;
  --brand-h1-weight: 700;
  --brand-h1-line-height: 1.1;
  --brand-h1-letter-spacing: -0.01em;

  --brand-h2-size: 36px;
  --brand-h2-weight: 700;
  --brand-h2-line-height: 1.15;
  --brand-h2-letter-spacing: -0.01em;

  --brand-h3-size: 24px;
  --brand-h3-weight: 700;
  --brand-h3-line-height: 1.3;
  --brand-h3-letter-spacing: 0;

  --brand-h4-size: 20px;
  --brand-h4-weight: 500;
  --brand-h4-line-height: 1.3;
  --brand-h4-letter-spacing: 0;

  --brand-body-lg-size: 18px;
  --brand-body-lg-weight: 400;
  --brand-body-lg-line-height: 1.6;

  --brand-body-size: 16px;
  --brand-body-weight: 400;
  --brand-body-line-height: 1.6;
  --brand-body-letter-spacing: 0;

  --brand-small-size: 14px;
  --brand-small-weight: 400;
  --brand-small-line-height: 1.5;

  --brand-caption-size: 12px;
  --brand-caption-weight: 400;
  --brand-caption-line-height: 1.5;
  --brand-caption-letter-spacing: 0.02em;

  /* === Spacing === */
  --brand-space-3xs: 2px;
  --brand-space-2xs: 4px;
  --brand-space-xs: 8px;
  --brand-space-sm: 12px;
  --brand-space-md: 16px;
  --brand-space-lg: 24px;
  --brand-space-xl: 32px;
  --brand-space-2xl: 48px;
  --brand-space-3xl: 64px;
  --brand-space-4xl: 96px;
  --brand-space-5xl: 128px;

  /* === Layout === */
  --brand-radius-none: 0;
  --brand-radius-sm: 4px;
  --brand-radius-md: 8px;
  --brand-radius-lg: 16px;
  --brand-radius-pill: 999px;
  --brand-max-width: 1200px;
  --brand-grid-columns: 12;
  --brand-grid-gutter: 24px;

  /* === SMM Template === */
  --brand-smm-ghost-text: #DDD5CA;
  --brand-bg-surface-blush: #E8DCD4;
  --brand-smm-category-size: 18px;
  --brand-smm-category-weight: 700;
  --brand-smm-category-tracking: 0.12em;
}

